.shape-sort-board {
  min-height: 360px;
  padding: 16px;
}

.shape-tile {
  width: 72px;
  height: 72px;
  border-radius: 18px;
  touch-action: none;
}

@media (max-width: 768px) {
  .shape-sort-board {
    padding: 20px;
  }

  .shape-tile {
    width: 88px;
    height: 88px;
    border-radius: 22px;
  }
}

const isMobileViewport = window.matchMedia('(max-width: 768px)').matches;

const shapeSortConfig = {
  tileSizePx: isMobileViewport ? 88 : 72,
  dragPaddingPx: isMobileViewport ? 18 : 6,
  snapTolerancePx: isMobileViewport ? 22 : 16,
};

